<template>
  <div class="analytics-dashboard">

    <div class="heading-border mb-4 mt-2">
      <h5 class="h5"><span>{{ $t('AnalyticsDashboard') }}</span></h5>
    </div>

    <div class="tab-style">
      <div class="tab_container mb-0">
        <ul class="nav nav-tabs all-tabs responsive-tabs cust flex-wrap newtabbb w-100">
          <li class="nav-item" v-for="(tab, index) in tabs">
            <a class="nav-link" :key="index" :class="['tab-button', { active: activeTab === index }]"
              @click="switchTab(index)">
              <i :class="tab.icon"></i> {{ tab.label }}
            </a>
          </li>
        </ul>
      </div>
    </div>


    <div class="dashboard-content float-left w-100 db_analytic mt-3">
      <RevenueAnalytics v-if="activeTab === 0" />
      <ProcessingAnalytics v-if="activeTab === 1" />
      <CustomerAnalytics v-if="activeTab === 2" />
      <GeographicDistribution v-if="activeTab === 3" :GeographicDistributionData="GeographicDistributionData" />
    </div>
  </div>
</template>

<script>
import { analyticsService } from '../../services/analyticsService';
import RevenueAnalytics from './components/RevenueAnalytics.vue';
import ProcessingAnalytics from './components/ProcessingAnalytics.vue';
import CustomerAnalytics from './components/CustomerAnalytics.vue';
import GeographicDistribution from '../AnalyticsDashboard/components/widgets/GeographicDistribution.vue';

export default {
  name: 'AnalyticsDashboard',
  created: async function () {
    //debugger
    const vm = this;
    vm.isLoading = true;

    try {
      await Promise.all([

        vm.GeographicDistribution(),

      ]);
    } catch (err) {
      console.error(err);
    } finally {
      vm.isLoading = false; // ✅ hides only after page is fully ready
    }
  },
  components: {
    RevenueAnalytics,
    ProcessingAnalytics,
    CustomerAnalytics,
    GeographicDistribution
  },
  data() {
    return {
      activeTab: 0,
      tabs: [
        { label: 'Revenue Analytics', icon: 'fa fa-money-bill-trend-up' },
        { label: 'Processing Analytics', icon: 'fa fa-cogs' },
        { label: 'Customer Analytics', icon: 'fa fa-users' },
        { label: 'Geographic Distribution', icon: 'fa fa-map' }
      ],
      GeographicDistributionData: [],
    };
  },
  methods: {
    switchTab(index) {
      this.activeTab = index;
    },
    async GeographicDistribution() {
      // debugger
      var vm = this;

      try {

        const response = await analyticsService.GetGeographicDistributionofTickets();
        if (response && response.data && response.data.result) {

          vm.GeographicDistributionData = response.data.result;


        }
      } catch (error) {
        console.error('Error loading total revenue trend:', error);
      } finally {

      }
    },
  }
};
</script>
