<template>
  <div class="widget-card dashboard-boxes graph-widget-box bg-white mt-2 mb-4" :class="{ fullscreen: isFullscreen }">

    <!-- ================= HEADER ================= -->
    <div class="widget-header graph-widget-heading float-left w-100">
      <div class="widget-title d-flex justify-content-between align-items-center w-100">

        <span>
          <em class="fas fa-money-bill-trend-up"></em>
          {{ $t('RevenueAnalytics') }} ({{ minYear }}-{{ maxYear }})
        </span>

        <div class="d-flex align-items-center gap-2">
          <small class="text-muted">
            {{ $t('Quarterlyrevenuetrends') }}
          </small>

          <!-- ✅ FULLSCREEN BUTTON -->
          <button class="fullscreen-btn" @click="toggleFullscreen">
            <em :class="isFullscreen
              ? 'fas fa-compress'
              : 'fas fa-expand'"></em>
          </button>
        </div>

      </div>
    </div>

    <!-- ================= BODY ================= -->
    <div class="p-3 w-100">

      <!-- Controls -->
      <div class="revenue-controls">
        <button v-for="btn in chartButtons" :key="btn.type" class="revenue-btn"
          :class="{ active: revenueChartType === btn.type }" @click="drawRevenueChart(btn.type)">
          {{ btn.label }}
        </button>
      </div>

      <!-- Chart -->
      <div id="revenueChart" class="chart-container"></div>

      <!-- Stats -->
      <div v-if="stats" class="revenue-stats">
        <div class="revenue-stat-box">
          <div class="revenue-stat-value">
            {{ formatCurrency(stats.currentQuarterRevenue) }}
          </div>
          <div class="revenue-stat-label">
            {{ $t('CurrentQuarterRevenue') }} (2026 Q1)
          </div>
        </div>

        <div class="revenue-stat-box">
          <div class="revenue-stat-value">
            {{ formatCurrency(stats.avgInvoiceValue) }}
          </div>
          <div class="revenue-stat-label">
            {{ $t('AverageInvoiceValue') }} (2026 Q1)
          </div>
        </div>

        <div class="revenue-stat-box">
          <div class="revenue-stat-value">
            {{ $n(stats.activeClients) }}
          </div>
          <div class="revenue-stat-label">
            {{ $t('ActiveClients') }} (2026 Q1)
          </div>
        </div>

        <div class="revenue-stat-box">
          <div class="revenue-stat-value">
            {{ stats.revenueGrowth }}
          </div>
          <div class="revenue-stat-label">
            {{ $t('QuarteroverQuarterGrowth') }}
          </div>
        </div>
      </div>

    </div>
  </div>
</template>

<script>
import * as Plotly from "plotly.js-dist";

export default {
  name: "RevenueAnalytics",

  props: {
    GetQuarterlyBillingStatsData: {
      type: String,
      default: () => []
    }
  },

  data() {
    return {
      revenueChartType: "Total_Revenue",
      isFullscreen: false,
      revenueData: [],
      minYear: null,
      maxYear: null,

      chartButtons: [
        { type: "Total_Revenue", label: "Total Revenue" },
        { type: "Average_Invoice_Value", label: "Average Invoice Value" },
        { type: "Active_Clients", label: "Active Clients" },
        { type: "Number_of_Invoices", label: "Number of Invoices" }
      ],

      stats: {
        currentQuarterRevenue: 13320000,
        avgInvoiceValue: 26586.83,
        activeClients: 246,
        revenueGrowth: "+5.3%"
      }
    };
  },

  mounted() {
    this.loadData();
    window.addEventListener("keydown", this.handleEsc);
  },

  beforeUnmount() {
    window.removeEventListener("keydown", this.handleEsc);
  },

  methods: {

    /* ================= FULLSCREEN ================= */

    toggleFullscreen() {
      this.isFullscreen = !this.isFullscreen;

      this.$nextTick(() => {
        setTimeout(() => {
          Plotly.Plots.resize("revenueChart");
        }, 300);
      });
    },

    handleEsc(e) {
      if (e.key === "Escape") {
        this.isFullscreen = false;
      }
    },

    /* ================= DATA ================= */

    loadData() {
      this.drawRevenueChart("Total_Revenue");
    },

    getMinMaxYear(data) {
      const years = data.map(d => d.Year);
      return {
        minYear: Math.min(...years),
        maxYear: Math.max(...years)
      };
    },

    formatCurrency(num) {
      if (num >= 1e9) return "$" + (num / 1e9).toFixed(2) + "B";
      if (num >= 1e6) return "$" + (num / 1e6).toFixed(1) + "M";
      if (num >= 1e3) return "$" + (num / 1e3).toFixed(1) + "K";
      return "$" + num.toFixed(2);
    },

    formatNumber(num) {
      if (num >= 1e6) return (num / 1e6).toFixed(1) + "M";
      if (num >= 1e3) return (num / 1e3).toFixed(1) + "K";
      return num.toString();
    },

    /* ================= CHART ================= */

    drawRevenueChart(type = "Total_Revenue") {

      this.revenueChartType = type;

      const level1 = JSON.parse(this.GetQuarterlyBillingStatsData);
      const level2 = JSON.parse(level1[0]);
      const obj = level2.find(x => x.key === "quarterlyData");

      this.revenueData = JSON.parse(obj.value);

      const result = this.getMinMaxYear(this.revenueData);
      this.minYear = result.minYear;
      this.maxYear = result.maxYear;

      const quarters = this.revenueData.map(
        d => d.Quarter_Period || `${d.Year}-Q${d.Quarter}`
      );

      const values = this.revenueData.map(d => d[type] || 0);

      const trace = {
        x: quarters,
        y: values,
        mode: "lines+markers",
        line: { color: "#3b82f6", width: 3, shape: "spline" },
        marker: { size: 6 }
      };

      const layout = {
        margin: { t: 60, b: 80, l: 80, r: 30 },
        paper_bgcolor: "transparent",
        plot_bgcolor: "transparent",
        xaxis: { tickangle: -45 },
        hovermode: "closest"
      };

      Plotly.newPlot(
        "revenueChart",
        [trace],
        layout,
        {
          responsive: true,
          displaylogo: false,
          modeBarButtons: [["toImage"]],
          toImageButtonOptions: {
            format: "png",
            filename: "Revenue_Analytics",
            height: 700,
            width: 1200,
            scale: 2
          }
        }
      );
    }
  }
};
</script>

<style>
/* ===== FULLSCREEN BUTTON ===== */
.fullscreen-btn {
  border: none;
  background: transparent;
  cursor: pointer;
  font-size: 16px;
}

/* ===== FULLSCREEN MODE ===== */
.widget-card.fullscreen {
  position: fixed !important;
  top: 0;
  left: 0;
  width: 100vw !important;
  height: 100vh !important;
  z-index: 99999999999999;
  background: #fff;
  padding: 15px;
  display: flex;
  flex-direction: column;
}

.widget-card.fullscreen .chart-container {
  flex: 1;
  height: 100% !important;
}

body:has(.widget-card.fullscreen) {
  overflow: hidden;
}
</style>