<template>
  <div class="widget-card dashboard-boxes graph-widget-box bg-white mt-2 mb-4" :class="{ fullscreen: isFullscreen }">
    <!-- HEADER -->
    <div class="widget-header graph-widget-heading float-left w-100 d-flex justify-content-between align-items-center">
      <div class="widget-title justify-content-between w-100">
        <span>
          <em class="fa fa-area-chart"></em>
          {{ $t('AgentPerformanceAverageTicketLocateTime') }}
        </span>

        <small class="text-muted text-center">
          {{ $t('Quarterlyaveragetimetaken') }} ({{ minYear }}-{{ maxYear }})
        </small>
      </div>

      <!-- FULLSCREEN BUTTON -->
      <em class="fa" :class="isFullscreen ? 'fa-compress' : 'fa-expand'" @click="toggleFullscreen"
        style="cursor:pointer;font-size:16px;margin-left:10px" title="Toggle Fullscreen"></em>
    </div>

    <div class="p-3 w-100">

      <!-- CHART -->
      <div id="agentTimeChart" class="chart-container"></div>

      <!-- STATS -->
      <div v-if="stats" class="revenue-stats">
        <div class="revenue-stat-box">
          <div class="revenue-stat-value">{{ stats.AvgLocateTime }} min</div>
          <div class="revenue-stat-label">{{ $t('AverageAcrossAllPeriods') }}</div>
        </div>

        <div class="revenue-stat-box">
          <div class="revenue-stat-value">{{ stats.peakLocateTime }} min</div>
          <div class="revenue-stat-label">{{ $t('PeakTime') }} (Q1 2023)</div>
        </div>

        <div class="revenue-stat-box">
          <div class="revenue-stat-value">{{ stats.improvementTrend }}</div>
          <div class="revenue-stat-label">{{ $t('IncreaseSince') }} 2020</div>
        </div>

        <div class="revenue-stat-box">
          <div class="revenue-stat-value">{{ stats.recentPerformance }} min</div>
          <div class="revenue-stat-label">{{ $t('Averagein') }} 2024</div>
        </div>
      </div>

    </div>
  </div>
</template>

<script>
import * as Plotly from 'plotly.js-dist';

export default {
  name: 'AgentPerformance',

  props: {
    AgentPerformenceData: {
      type: String,
      required: false,
      default: () => []
    }
  },

  data() {
    return {
      loading: false,
      stats: null,
      minYear: null,
      maxYear: null,
      isFullscreen: false
    };
  },

  mounted() {
    this.loadData();
    window.addEventListener('keydown', this.handleEsc);
  },

  beforeUnmount() {
    window.removeEventListener('keydown', this.handleEsc);
  },

  methods: {

    /* ======================
       FULLSCREEN
    ====================== */

    toggleFullscreen() {
      this.isFullscreen = !this.isFullscreen;

      this.$nextTick(() => {
        Plotly.Plots.resize('agentTimeChart');
      });
    },

    handleEsc(e) {
      if (e.key === 'Escape' && this.isFullscreen) {
        this.toggleFullscreen();
      }
    },

    /* ======================
       DATA LOGIC (UNCHANGED)
    ====================== */

    getMinMaxYear(data) {
      const years = data.map(item => item.YEAR);
      return {
        minYear: Math.min(...years),
        maxYear: Math.max(...years)
      };
    },

    loadData() {
      this.loading = true;

      try {
        const rawResponse = this.AgentPerformenceData;
        const level1 = JSON.parse(rawResponse);
        const level2 = JSON.parse(level1[0]);
        const performanceObj = level2.find(item => item.key === "performanceData");

        this.AgentPerformenceDataextract = JSON.parse(performanceObj.value);

        const result = this.getMinMaxYear(this.AgentPerformenceDataextract);
        this.minYear = result.minYear;
        this.maxYear = result.maxYear;

        const avg =
          this.AgentPerformenceDataextract.reduce((s, d) => s + d.AvgLocateTime, 0) /
          this.AgentPerformenceDataextract.length;

        const peak = Math.max(...this.AgentPerformenceDataextract.map(d => d.AvgLocateTime));
        const peakData = this.AgentPerformenceDataextract.find(d => d.AvgLocateTime === peak);

        const startAvg =
          this.AgentPerformenceDataextract.slice(0, 4)
            .reduce((s, d) => s + d.AvgLocateTime, 0) / 4;

        const endAvg =
          this.AgentPerformenceDataextract.slice(-4)
            .reduce((s, d) => s + d.AvgLocateTime, 0) / 4;

        const improvement = (((endAvg - startAvg) / startAvg) * 100).toFixed(0);

        const recentAvg =
          this.AgentPerformenceDataextract
            .filter(d => d.YEAR === 2024)
            .reduce((s, d) => s + d.AvgLocateTime, 0) / 4;

        this.stats = {
          AvgLocateTime: avg.toFixed(2),
          peakLocateTime: peak.toFixed(2),
          improvementTrend: `+${improvement}%`,
          recentPerformance: recentAvg.toFixed(2),
          peakData
        };

        this.drawChart();

      } catch (error) {
        console.error('Error loading agent performance:', error);
      } finally {
        this.loading = false;
      }
    },

    /* ======================
       DRAW CHART
    ====================== */

    drawChart() {

      const quarters = this.AgentPerformenceDataextract.map(
        d => `Q${d.QUARTER} ${d.YEAR}`
      );

      const locateTimes =
        this.AgentPerformenceDataextract.map(d => d.AvgLocateTime);

      const mainTrace = {
        x: quarters,
        y: locateTimes,
        type: 'scatter',
        mode: 'lines+markers',
        name: 'Average Locate Time',
        line: { color: '#ec4899', width: 3, shape: 'spline' },
        marker: { size: 6, color: '#ec4899' }
      };

      /* Trend Line */
      const xValues = quarters.map((_, i) => i);
      const n = xValues.length;

      const sumX = xValues.reduce((a, b) => a + b, 0);
      const sumY = locateTimes.reduce((a, b) => a + b, 0);
      const sumXY = xValues.reduce((s, x, i) => s + x * locateTimes[i], 0);
      const sumXX = xValues.reduce((s, x) => s + x * x, 0);

      const slope = (n * sumXY - sumX * sumY) / (n * sumXX - sumX * sumX);
      const intercept = (sumY - slope * sumX) / n;

      const trendTrace = {
        x: quarters,
        y: xValues.map(x => slope * x + intercept),
        type: 'scatter',
        mode: 'lines',
        name: 'Trend Line',
        line: { color: 'rgba(236,72,153,0.5)', width: 2, dash: 'dash' }
      };

      const layout = {
        margin: { t: 30, b: 80, l: 80, r: 30 },
        paper_bgcolor: 'transparent',
        plot_bgcolor: 'transparent',
        autosize: true,
        xaxis: { tickangle: -45, automargin: true },
        yaxis: { automargin: true },
        hovermode: 'closest',
        legend: { orientation: 'h', y: -0.2, x: 0.5, xanchor: 'center' }
      };

      Plotly.newPlot(
        'agentTimeChart',
        [mainTrace, trendTrace],
        layout,
        {
          responsive: true,
          displaylogo: false,
          modeBarButtons: [["toImage"]],
          toImageButtonOptions: {
            format: "png",
            filename: "Agent_Performance_Average_Ticket_Locate_Time",
            height: 700,
            width: 1000,
            scale: 2
          }
        }
      );
    }
  }
};
</script>

<style scoped>
/* NORMAL */
.chart-container {
  width: 100%;
  height: 400px;
}

/* FULLSCREEN */
.fullscreen {
  position: fixed !important;
  inset: 0;
  width: 100vw !important;
  height: 100vh !important;
  z-index: 999999999;
  margin: 0 !important;
  padding: 20px;
  background: #ffffff;
}

.fullscreen .chart-container {
  height: calc(100vh - 180px) !important;
}

.widget-card {
  transition: all 0.25s ease;
}
</style>