<template>
  <div class="revenue-analytics w-100 float-left">
    <div class="widgets-grid_mainsingle">
      <div class="border p-3 bg-light">
        <!-- Controls -->
        <div class="controls " style="background: #f2f2f2;">
          <div class="control-group form-group">
            <!-- <div class="control-label"><i class="fas fa-calendar-alt"></i> Year Filter</div> -->
            <label>{{ $t('YearFilter') }}:</label>
            <div class="year-filter">
              <button v-for="year in years" :key="year" class="year-btn" :class="{ active: currentYear === year }"
                @click="updateYearFilter(year)">
                {{ year === 'all' ? 'All Years' : year }}
              </button>
            </div>
          </div>

          <div class="control-group form-group">
            <!-- <div class="control-label"><i class="fas fa-filter"></i> Display States</div> -->

            <label>{{ $t('DisplayStates') }}:</label>
            <select class="form-control w-100" v-model="topFilter" @change="updateBarChart">
              <option value="10">Top 10 States</option>
              <option value="15">Top 15 States</option>
              <option value="20">Top 20 States</option>
              <option value="all">All States</option>
            </select>
          </div>

          <div class="control-group form-group">
            <label>{{ $t('SearchState') }}:</label>

            <select class="form-control w-100" v-model="selectedState" @change="updateBarChart">
              <option value="">All States</option>

              <option v-for="state in sortedStates" :key="state.code" :value="state.code">
                {{ state.name }} ({{ state.code }})
              </option>

            </select>
          </div>

          <div class="control-group form-group">
            <!-- <div class="control-label"><i class="fas fa-info-circle"></i> Info</div> -->
            <label>{{ $t('Info') }}:</label>
            <button @click="resetView" class="reset-btn btn btn-primary">
              <em class="fas fa-sync-alt mr-2"></em>{{ $t('ResetMapView') }}
            </button>
          </div>
        </div>


        <div class="widgets-grid mt-2">

          <!-- Bar Chart Card -->
          <div class="widget-card dashboard-boxes graph-widget-box bg-white border">
            <div class="widget-header graph-widget-heading float-left w-100">
              <div class="widget-title justify-content-between">
                <span><em class="fas fa-chart-bar"></em> {{ $t('StateRankings') }}</span>
                <small class="text-muted text-center">{{ $t('Clickbarzoom') }}</small>
                <span><span class="metric-badge">{{ chartMetricBadge }}</span></span>
              </div>
              <!-- <div style="font-size: 14px; color: #7f8c8d; margin-top: 5px;">
          Click on a bar to zoom map to that state
        </div> -->
            </div>
            <div class="bar-chart-scroll">
              <div id="barChart"></div>
            </div>

          </div>

          <!-- Map Card -->
          <div class="widget-card dashboard-boxes graph-widget-box bg-white border">
            <div class="widget-header graph-widget-heading float-left w-100">
              <div class="widget-title justify-content-between">
                <span><em class="fas fa-map-marked-alt"></em> {{ $t('GeographicDistribution') }} </span>
                <small class="text-muted text-center">{{ $t('Clickzoom') }}</small>
                <span><span class="metric-badge">{{ mapMetricBadge }}</span></span>
              </div>

            </div>
            <div id="map"></div>

          </div>

        </div>

        <div class="widgets-grid">
          <div class="mini-stats">
            <!-- Dynamic stats will be inserted here -->
          </div>
        </div>




      </div>
    </div>
  </div>

</template>

<script>
import * as Plotly from 'plotly.js-dist';

export default {
  name: 'GeographicDistribution',
  data() {
    return {
      currentYear: 'all',
      topFilter: 'all',
      stateSearch: '',
      mapMetricBadge: 'Tickets',
      chartMetricBadge: 'Tickets',

      professionalTealScale: [
        [0.0, "#e6f2f2"],
        [0.25, "#99cccc"],
        [0.5, "#4da6a6"],
        [0.75, "#006666"],
        [1.0, "#003d4d"]
      ],
      years: [],
      selectedState: "",
      states: {
        "AL": "Alabama", "AK": "Alaska", "AZ": "Arizona", "AR": "Arkansas", "CA": "California",
        "CO": "Colorado", "CT": "Connecticut", "DE": "Delaware", "FL": "Florida", "GA": "Georgia",
        "HI": "Hawaii", "ID": "Idaho", "IL": "Illinois", "IN": "Indiana", "IA": "Iowa",
        "KS": "Kansas", "KY": "Kentucky", "LA": "Louisiana", "ME": "Maine", "MD": "Maryland",
        "MA": "Massachusetts", "MI": "Michigan", "MN": "Minnesota", "MS": "Mississippi", "MO": "Missouri",
        "MT": "Montana", "NE": "Nebraska", "NV": "Nevada", "NH": "New Hampshire", "NJ": "New Jersey",
        "NM": "New Mexico", "NY": "New York", "NC": "North Carolina", "ND": "North Dakota", "OH": "Ohio",
        "OK": "Oklahoma", "OR": "Oregon", "PA": "Pennsylvania", "RI": "Rhode Island", "SC": "South Carolina",
        "SD": "South Dakota", "TN": "Tennessee", "TX": "Texas", "UT": "Utah", "VT": "Vermont",
        "VA": "Virginia", "WA": "Washington", "WV": "West Virginia", "WI": "Wisconsin", "WY": "Wyoming",
        "DC": "District of Columbia", "AB": "Alberta"
      }

    };
  },
  computed: {
    sortedStates() {
      return Object.entries(this.states)
        .sort((a, b) => a[1].localeCompare(b[1])) // sort by state name
        .map(([code, name]) => ({ code, name }));
    }
  },
  props: {
    GeographicDistributionData: {
      type: String,
      required: false,
      default: () => []
    }
  },
  mounted() {
    var vm = this;
    if (Plotly) {
      vm.drawMap();
      vm.updateBarChart();
    } else {
      console.error('Plotly library not found. Please include Plotly.js in your project.');
    }

    window.addEventListener('resize', vm.handleResize);

    vm.years = this.getYearsList();
  },
  beforeUnmount() {
    window.removeEventListener('resize', this.handleResize);
  },
  watch: {
    currentYear() {
      this.drawMap();
      this.updateBarChart();
    }
  },
  methods: {
    getYearsList() {
      const currentYear = new Date().getFullYear();

      return [
        'all',
        (currentYear - 2).toString(),
        (currentYear - 1).toString(),
        currentYear.toString()
      ];
    },
    getStateName(code) {
      return this.states[code] || code;
    },
    formatNumber(num) {
      if (num >= 1000000) return (num / 1000000).toFixed(1) + 'M';
      if (num >= 1000) return (num / 1000).toFixed(1) + 'K';
      return num.toString();
    },
    getAggregatedData(yearFilter = "all") {
      var vm = this;
      const aggregated = {};

      const rawResponse = vm.GeographicDistributionData;
      const level1 = JSON.parse(rawResponse);
      const level2 = JSON.parse(level1[0]);
      const dataObj = level2.find(item => item.key === "data");
      vm.ticketData = JSON.parse(dataObj.value);

      vm.ticketData.forEach(item => {
        if (yearFilter === "all" || item.Year.toString() === yearFilter) {
          if (!aggregated[item.State]) {
            aggregated[item.State] = 0
          }
          aggregated[item.State] += item.TicketCount
        }
      })

      const result = Object.keys(aggregated).map(state => ({
        state: state,
        tickets: aggregated[state]
      }))

      result.sort((a, b) => b.tickets - a.tickets);

      return result;
    },
    updateMapStats(aggregatedData) {
      var vm = this;
      const mapStatsElement = document.querySelector('.mini-stats');
      if (!mapStatsElement) return;

      const yearText = vm.currentYear === "all" ? "2024-2026" : vm.currentYear;

      if (aggregatedData.length > 0) {
        const totalTickets = aggregatedData.reduce((sum, d) => sum + d.tickets, 0);
        const topState = aggregatedData[0];

        mapStatsElement.innerHTML = `
          <div class="mini-stat">
            <div class="mini-stat-value">${vm.formatNumber(totalTickets)}</div>
            <div class="mini-stat-label">Total Tickets (${yearText})</div>
          </div>
          <div class="mini-stat">
            <div class="mini-stat-value">${topState.state}</div>
            <div class="mini-stat-label">Top State: ${vm.formatNumber(topState.tickets)}</div>
          </div>
          <div class="mini-stat">
            <div class="mini-stat-value">${aggregatedData.length}</div>
            <div class="mini-stat-label">States with Data</div>
          </div>
        `;
      } else {
        mapStatsElement.innerHTML = `
          <div class="mini-stat">
            <div class="mini-stat-value">0</div>
            <div class="mini-stat-label">No data for ${yearText}</div>
          </div>
        `;
      }
    },
    drawMap() {
      var vm = this;
      if (!Plotly) return;

      const aggregatedData = vm.getAggregatedData(vm.currentYear);
      const metricLabel = "Tickets";
      vm.mapMetricBadge = metricLabel;

      const locations = aggregatedData.map(d => d.state);
      const zValues = aggregatedData.map(d => d.tickets);

      vm.updateMapStats(aggregatedData);

      // const trace = {
      //   type: "choropleth",
      //   locationmode: "USA-states",
      //   locations: locations,
      //   z: zValues,
      //   text: aggregatedData.map(d => {
      //     const stateName = vm.getStateName(d.state);
      //     const yearText = vm.currentYear === "all" ? "2024-2026" : vm.currentYear;
      //     return `<b>${stateName} (${d.state})</b><br>` +
      //       `Tickets (${yearText}): ${d.tickets.toLocaleString()}<br>` +
      //       `Rank: #${aggregatedData.findIndex(item => item.state === d.state) + 1}`;
      //   }),
      //   hoverinfo: "text",
      //   colorscale: vm.professionalTealScale,
      //   colorbar: {
      //     title: metricLabel,
      //     tickformat: ",",
      //     titlefont: { size: 14 },
      //     tickfont: { size: 12 }
      //   },
      //   marker: {
      //     line: {
      //       color: "white",
      //       width: 1
      //     }
      //   }
      // }
      const trace = {
        type: "choropleth",
        locationmode: "USA-states",
        locations: locations,

        // 👇 focus coloring
        z: locations.map((s, i) =>
          !vm.selectedState || s === vm.selectedState
            ? zValues[i]
            : 0.01   // tiny value → grey
        ),

        colorscale: vm.selectedState
          ? [
            [0, "#e5e7eb"],   // greyed states
            [0.05, "#e5e7eb"],
            [0.06, "#cfeeee"],
            [1, "#1f7a7a"]
          ]
          : vm.professionalTealScale,

        text: aggregatedData.map(d => {
          const stateName = vm.getStateName(d.state);
          const yearText = vm.currentYear === "all" ? "2024-2026" : vm.currentYear;

          return `<b>${stateName} (${d.state})</b><br>
            Tickets (${yearText}): ${d.tickets.toLocaleString()}`;
        }),

        hoverinfo: "text",

        marker: {
          line: {
            color: locations.map(s =>
              s === vm.selectedState ? "#000000" : "white"
            ),
            width: locations.map(s =>
              s === vm.selectedState ? 4 : 1
            )
          }
        },

        colorbar: {
          title: metricLabel,
          tickformat: ","
        }
      };

      const layout = {
        geo: {
          scope: "usa",
          showlakes: true,
          lakecolor: "#e6f2f2",
          showland: true,
          landcolor: "#f8fafc",
          subunitcolor: "white",
          countrycolor: "white",
          bgcolor: "#ffffff",
          showframe: false
        },
        margin: { t: 0, b: 0, l: 0, r: 30 },
        paper_bgcolor: "#ffffff",
        plot_bgcolor: "#ffffff"
      };

      Plotly.newPlot("map", [trace], layout, {
        responsive: true,
        displaylogo: false,
        modeBarButtons: [["toImage"]], // only PNG button
        toImageButtonOptions: {
          format: "png",
          filename: `Geographic_Distribution`,
          height: 700,
          width: 1000,
          scale: 2
        }
      }).then(() => {

        const mapElement = document.getElementById("map");

        const MIN_ZOOM = 1;
        const MAX_ZOOM = 4;

        mapElement.on("plotly_relayout", (event) => {

          if (event["geo.projection.scale"]) {

            let scale = event["geo.projection.scale"];

            if (scale < MIN_ZOOM) {
              Plotly.relayout("map", { "geo.projection.scale": MIN_ZOOM });
            }

            if (scale > MAX_ZOOM) {
              Plotly.relayout("map", { "geo.projection.scale": MAX_ZOOM });
            }

          }

        });

      });

    },
    updateBarChart() {
      debugger;
      var vm = this;
      if (!Plotly) return;

      const metricLabel = "Tickets";
      vm.chartMetricBadge = metricLabel;

      let filtered = vm.getAggregatedData(vm.currentYear);

      if (vm.selectedState) {
        filtered = filtered.filter(d => d.state === vm.selectedState);
        vm.zoomToState(vm.selectedState);
      }
      vm.drawMap();

      if (vm.topFilter !== "all") {
        filtered = filtered.slice(0, parseInt(vm.topFilter));
      }

      const trace = {
        type: "bar",
        orientation: "h",
        y: filtered.map(d => `${vm.getStateName(d.state)} (${d.state})`),
        x: filtered.map(d => d.tickets),
        width: filtered.length === 1
          ? [0.15]   // ⭐ very slim bar
          : filtered.map(() => 0.7),
        height: filtered.length === 1
          ? 220     // compact height for single bar
          : Math.max(400, filtered.length * 22),
        marker: {
          color: filtered.map(d => d.tickets),
          colorscale: vm.professionalTealScale,
          line: {
            color: "white",
            width: 1
          }
        },
        hovertemplate:
          "<b>%{y}</b><br>" +
          `Tickets (${vm.currentYear === "all" ? "2024-2026" : vm.currentYear}): %{x:,}` +
          "<extra></extra>",
        text: filtered.map(d => vm.formatNumber(d.tickets)),
        textposition: "outside"
      };

      const yearText = vm.currentYear === "all" ? "2024-2026" : vm.currentYear;

      const layout = {
        title: {
          text: `State Rankings by Ticket Count (${yearText})`,
          font: { size: 16, color: "#2c3e50" }
        },
        xaxis: {
          title: "Number of Tickets",
          tickformat: ",",
          gridcolor: "#f1f1f1"
        },
        yaxis: {
          autorange: "reversed",
          tickfont: { size: 10 },
          automargin: true
        },
        margin: { l: 180, r: 30, t: 60, b: 60 },
        height: Math.max(400, filtered.length * 22),
        paper_bgcolor: "transparent",
        plot_bgcolor: "transparent"
      };

      Plotly.newPlot("barChart", [trace], layout, {
        responsive: true,
        displaylogo: false,
        modeBarButtons: [["toImage"]],
        toImageButtonOptions: {
          format: "png",
          filename: `State_Rankings`,
          height: layout.height,
          width: 1000,
          scale: 2
        }
      });

      const barChartElement = document.getElementById("barChart");
      if (barChartElement) {
        // barChartElement.on("plotly_click", e => {
        //   const stateCode = e.points[0].y.match(/\(([A-Z]{2})\)/)[1];
        //   vm.zoomToState(stateCode);
        // });
        barChartElement.on("plotly_click", e => {
          const stateCode = e.points[0].y.match(/\(([A-Z]{2})\)/)[1];

          vm.selectedState = stateCode;
          vm.zoomToState(stateCode);
          vm.drawMap();
          vm.updateBarChart();
        });
      }
    },
    zoomToState(state) {
      var vm = this;
      const centers = {
        TX: { lat: 31, lon: -99 }, CA: { lat: 37, lon: -120 }, FL: { lat: 27, lon: -81 },
        NY: { lat: 43, lon: -75 }, IL: { lat: 40, lon: -89 }, NC: { lat: 35.5, lon: -79 },
        OH: { lat: 40.5, lon: -82.5 }, PA: { lat: 40.9, lon: -77.6 }, MI: { lat: 44.3, lon: -85.5 },
        GA: { lat: 33, lon: -83.5 }, NJ: { lat: 40.2, lon: -74.7 }, VA: { lat: 37.5, lon: -78.5 },
        WA: { lat: 47.5, lon: -120.5 }, MA: { lat: 42.4, lon: -71.5 }, AZ: { lat: 34.3, lon: -111.7 },
        CO: { lat: 39, lon: -105.5 }, IN: { lat: 39.8, lon: -86.3 }, MO: { lat: 38.5, lon: -92.5 },
        TN: { lat: 35.8, lon: -86.4 }, MD: { lat: 39, lon: -76.8 }, WI: { lat: 44.5, lon: -89.5 },
        MN: { lat: 46, lon: -94 }, SC: { lat: 33.9, lon: -80.9 }, AL: { lat: 32.8, lon: -86.8 },
        LA: { lat: 31, lon: -91.8 }, KY: { lat: 37.5, lon: -85 }, OR: { lat: 44, lon: -120.5 },
        OK: { lat: 35.5, lon: -97.5 }, CT: { lat: 41.6, lon: -72.7 }, IA: { lat: 42, lon: -93.5 },
        MS: { lat: 32.7, lon: -89.7 }, AR: { lat: 34.9, lon: -92.4 }, UT: { lat: 39.5, lon: -111.5 },
        KS: { lat: 38.5, lon: -98 }, NV: { lat: 39.5, lon: -116.5 }, NM: { lat: 34.5, lon: -106 },
        NE: { lat: 41.5, lon: -99.5 }, WV: { lat: 38.6, lon: -80.6 }, ID: { lat: 44.5, lon: -114.5 },
        NH: { lat: 44, lon: -71.5 }, ME: { lat: 45.3, lon: -69.2 }, HI: { lat: 20.8, lon: -156.3 },
        RI: { lat: 41.7, lon: -71.5 }, MT: { lat: 47, lon: -110 }, DE: { lat: 39, lon: -75.5 },
        SD: { lat: 44.5, lon: -100.2 }, ND: { lat: 47.5, lon: -100.5 }, AK: { lat: 64, lon: -150 },
        VT: { lat: 44, lon: -72.7 }, WY: { lat: 43, lon: -107.5 }, DC: { lat: 38.9, lon: -77 },
        AB: { lat: 53, lon: -115 }
      }

      const center = centers[state] || { lat: 39, lon: -98 };

      if (Plotly) {
        Plotly.relayout("map", {
          "geo.center": center,
          "geo.projection.scale": 3
        });
      }
    },
    updateYearFilter(year) {
      var vm = this;
      vm.currentYear = year;
      vm.drawMap();
      vm.updateBarChart();
    },
    resetView() {
      var vm = this;
      if (Plotly) {
        Plotly.relayout("map", {
          "geo.center": { lat: 39, lon: -98 },
          "geo.projection.scale": 1
        });
        vm.stateSearch = null;
        vm.selectedState = '';
        vm.topFilter = 'all';
        vm.currentYear = 'all';
        vm.updateBarChart();
      }
    },
    handleResize() {
      var vm = this;
      if (Plotly) {
        if (document.getElementById('map')) {
          Plotly.Plots.resize(document.getElementById('map'));
        }
        if (document.getElementById('barChart')) {
          Plotly.Plots.resize(document.getElementById('barChart'));
        }
      }
    }
  }
};
</script>
<style>
.bar-chart-scroll {
  max-height: 650px;
  overflow-y: auto;
}
</style>